const payload = $json;
const input = payload.input ?? {};
if (input.benefitSlug !== 'roi-calculator') {
  return [{ json: {
    followup_required: false,
    followupQuestions: [],
    result: {
      score: 0,
      summary: `benefitSlug must be roi-calculator`,
      recommendation: 'Send request to the matching benefit workflow.'
    }
  } }];
}
const answers = Array.isArray(input.answers) ? input.answers : [];
const answersMap = answers.reduce((acc, item) => {
  if (item && item.questionId) acc[item.questionId] = item.value;
  return acc;
}, {});
const stage = input.stage ?? 'standard_started';
const followup_required = stage !== 'standard_completed';
const followupQuestions = followup_required
  ? [{
      id: 'q1',
      prompt: `Please provide one more detail for ${input.benefitSlug}: current baseline metric and target outcome.`
    }]
  : [];
return [{
  json: {
    session: payload.session ?? {},
    input,
    prompts: payload.prompts ?? {},
    answersMap,
    followup_required,
    followupQuestions
  }
}];

if ($json.followup_required) {
  return [{ json: { ...$json, score: 0, ragContext: { reason: 'Waiting for follow-up answers' } } }];
}
const answersMap = $json.answersMap ?? {};
const annualRevenue = Number(answersMap.annualRevenue ?? 0);
const quoteTurnaroundDays = Number(answersMap.quoteTurnaroundDays ?? 0);
const winRate = Number(answersMap.winRate ?? 0);
const score = Math.max(0, Math.min(100, Math.round((annualRevenue / 2000) + (100 - quoteTurnaroundDays * 3) + (winRate * 1.5))));
return [{ json: { ...$json, ragContext: { annualRevenue, quoteTurnaroundDays, winRate }, score } }];

if ($json.followup_required) {
  return [{
    json: {
      followup_required: true,
      followupQuestions: $json.followupQuestions,
      result: {
        score: 0,
        summary: 'Additional input is required before final scoring.',
        recommendation: 'Answer the follow-up question(s) and submit again.'
      }
    }
  }];
}
const systemPrompt = $json.prompts?.system ?? '';
const userPrompt = $json.prompts?.user ?? '';
const ragHint = (systemPrompt || userPrompt)
  ? ' Mock LLM RAG grounded this response on provided prompts.'
  : '';
return [{
  json: {
    followup_required: false,
    followupQuestions: [],
    result: {
      score: $json.score,
      summary: 'You can reduce quote cycle by 15% by automating quote orchestration.' + ragHint,
      recommendation: 'Automate pricing approvals and create reusable quote templates.'
    }
  }
}];
